import React from "react";
import CartItem from "../../components/CartItem";

const CartPage = ({ cartItems, openDeleteModal }) => {

    return (
        <>
            <h1>CART</h1>
            <div style={{ display: 'flex', flexWrap: 'wrap' }}>
                {cartItems && cartItems.map(item => <CartItem key={item.name} {...item} openDeleteModal={openDeleteModal} />)}
            </div>
        </>
    )
}

export default CartPage;