import React from "react";
import Item from "../../components/Item";

const HomePage = ({ items, openCartModal, toggleFavorite }) => {

    return (
        <div>
            <h1>HOME</h1>
            <div style={{ display: 'flex', flexWrap: 'wrap' }}>
            {items && items.map(item => <Item key={item.id} {...item} openCartModal={openCartModal} toggleFavorite={toggleFavorite} />)}
            </div>
        </div>
    )
}

export default HomePage;